class Solution {
public:
    int removeElement(vector<int>& nums, int val) {
        int el_size = 0;

        for (int i = 0; i < nums.size(); i++){
            if(nums[i] != val){
                nums[el_size] = nums[i];
                el_size++;
            }

        }

        return el_size;

    }
};
